# constructor.py# Единый конструктор ссылок (с принтами для отладки)import jsonimport loggingfrom bot.bank import choose_countryfrom bot.parsers import parse_and_validatefrom bot.states import *from bot.states import STEP_CHOICE, STEP_INPUTfrom bot.types_config import CATEGORIES, LINK_TYPES, get_types_by_category, get_stepfrom bot.utils import get_db_connection, get_or_create_userfrom telegram import Update, InlineKeyboardButton, InlineKeyboardMarkupfrom telegram.ext import ContextTypes, ConversationHandler, CommandHandler, CallbackQueryHandler, MessageHandler, \    filterslogger = logging.getLogger(__name__)# ===== ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ =====async def get_page_id(context: ContextTypes.DEFAULT_TYPE, user_id: int) -> int:	"""Получить page_id пользователя"""	conn = await get_db_connection()	try:		db_user = await get_or_create_user(conn, user_id, None, None, None)		page = await conn.fetchrow("SELECT id FROM pages WHERE user_id = $1", db_user['id'])		return page['id'] if page else None	finally:		await conn.close()def build_categories_keyboard() -> InlineKeyboardMarkup:	"""Построить клавиатуру с категориями"""	keyboard = []	row = []	for i, (cat_id, cat_data) in enumerate(CATEGORIES.items()):		btn_text = cat_data['name']  # "💬 Мессенджеры"		callback = f"cat_{cat_id}"  # f"cat_messengers"		print(f"  🏷️  Кнопка: {btn_text} -> {callback}")		row.append(InlineKeyboardButton(btn_text, callback_data=callback))		if len(row) == 2:			keyboard.append(row)			row = []	if row:		keyboard.append(row)	keyboard.append([InlineKeyboardButton("◀️ Назад в меню", callback_data="back_to_main")])	return InlineKeyboardMarkup(keyboard)def build_types_keyboard(category: str) -> InlineKeyboardMarkup:	"""Построить клавиатуру с типами ссылок для категории"""	types = get_types_by_category(category)	print(f"  🏷️  Типы в категории {category}: {list(types.keys())}")		keyboard = []	row = []	for i, (type_id, type_data) in enumerate(types.items()):		btn_text = type_data['name']		callback = f"type_{type_id}"		row.append(InlineKeyboardButton(btn_text, callback_data=callback))		if len(row) == 2:			keyboard.append(row)			row = []	if row:		keyboard.append(row)	keyboard.append([InlineKeyboardButton("◀️ Назад к категориям", callback_data="back_to_categories")])	return InlineKeyboardMarkup(keyboard)# ===== ОБРАБОТЧИКИ =====async def start_constructor(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Точка входа: показать категории"""	print("\n" + "=" * 60)	print("🔧 Вызвана start_constructor\nНажата Добавить ссылку\n\n")		# В любом обработчике внутри ConversationHandler	print(f"  🔄 ТЕКУЩЕЕ СОСТОЯНИЕ ДИАЛОГА (которое ВОЗВРАЩАЕТСЯ): {context.user_data.get('_state', 'НЕТ СОСТОЯНИЯ')}")		# ===== ОЧИСТКА СТАРЫХ ДАННЫХ =====	keys_to_clear = ['category', 'link_type', 'step_index', 'collected_data', 'type_config']	for key in keys_to_clear:		if key in context.user_data:			del context.user_data[key]			print(f"  🧹 Очищено: {key}")	# =================================		query = update.callback_query	if query:		await query.answer()		print(f"  📩 callback_data: {query.data}")		user_id = query.from_user.id	else:		print(f"  📩 команда: /addlink")		user_id = update.message.from_user.id		print(f"  👤 user_id: {user_id}")	print(f"  📊 user_data keys: {list(context.user_data.keys())}")		# Проверка лимита ссылок (можно добавить позже)		text = "📁 **Выбери категорию** для новой ссылки:"	keyboard = build_categories_keyboard()		if query:		await query.edit_message_text(text, reply_markup=keyboard, parse_mode='Markdown')		print("  ✅ Отправлено меню категорий (edit)")	else:		await update.message.reply_text(text, reply_markup=keyboard, parse_mode='Markdown')		print("  ✅ Отправлено меню категорий (reply)")		print("=" * 60)	print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ:{WAIT_CONSTRUCTOR_CATEGORY}")	return WAIT_CONSTRUCTOR_CATEGORYasync def handle_category(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Обработка выбора категории"""	print("\n" + "=" * 60)		print("🔧 \nВызвана handle_category\nНажата кнопка Одной из категорий")		query = update.callback_query	await query.answer()		# Только если это действительно категория	if not query.data.startswith("cat_"):		print(f"  ⚠️ Это не категория: {query.data}")		return		# В handle_category ты заменяешь cat_ на категорию (messengers)	category = query.data.replace("cat_", "")	print(f"  📩 callback_data: {query.data}")	print(f"  🏷️  Выбрана категория: {category}")		from bot.link_constructor import wallets_and_crypto_menu		if category == "transfers":		print(f"  🏦 Перенаправляем в банковский раздел")		# Вызываем функцию выбора страны из bank.py		return await choose_country(update, context)		if category == "crypto":		print(f"  🏦 Перенаправляем в кошельковый раздел")		# Вызываем функцию выбора страны из bank.py		return await wallets_and_crypto_menu(update, context)		context.user_data['category'] = category	print(f"  💾 Сохранено в user_data['category'] = {category}")		cat_data = CATEGORIES.get(category, {})	text = f"**{cat_data.get('name', category)}**\n\n{cat_data.get('description', '')}\n\n👇 **Выбери тип:**"		keyboard = build_types_keyboard(category)		await query.edit_message_text(text, reply_markup=keyboard, parse_mode='Markdown')	print(f"  ✅ Показаны типы для {category}")	print("=" * 60)		print(f"  🔄 ДИАЛОГ ПЕРЕХОДИТ В СОСТОЯНИЕ: WAIT_CONSTRUCTOR_TYPE ({WAIT_CONSTRUCTOR_TYPE})")	return WAIT_CONSTRUCTOR_TYPEasync def handle_type(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Обработка выбора типа ссылки"""	print("\n" + "=" * 60)	print("🔧 handle_type ВЫЗВАН")		query = update.callback_query	await query.answer()		type_id = query.data.replace("type_", "")	print(f"  📩 callback_data: {query.data}")	print(f"  🏷️  Выбран тип: {type_id}")		context.user_data['link_type'] = type_id	context.user_data['step_index'] = 0	context.user_data['collected_data'] = {}		# Получаем конфиг типа	type_config = LINK_TYPES.get(type_id)	if not type_config:		print(f"  ❌ ОШИБКА: тип {type_id} не найден в LINK_TYPES!")		await query.edit_message_text("❌ Ошибка: тип не найден")		return WAIT_CONSTRUCTOR_TYPE  # ← вернуться к выбору типа		print(f"  📋 Конфиг типа:")	print(f"    • name: {type_config.get('name')}")	print(f"    • category: {type_config.get('category')}")	print(f"    • steps: {len(type_config.get('steps', []))} шагов")		context.user_data['type_config'] = type_config		# Начинаем первый шаг	print(f"  🚀 Запуск первого шага (index=0)")	print("=" * 60)	print(f"🔍 _state В handle_type: {context.user_data.get('_state')}")		return await process_current_step(update, context)async def process_current_step(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Обработать текущий шаг"""	print("\n" + "=" * 60)	print("🔧 process_current_step ВЫЗВАН")	print(f"  🔍 _state ДО: {context.user_data.get('_state')}")		query = update.callback_query	step_index = context.user_data.get('step_index', 0)	type_config = context.user_data.get('type_config')		print(f"  📍 Текущий шаг index: {step_index}")	print(f"  📊 collected_data: {context.user_data.get('collected_data', {})}")		if not type_config:		print(f"  ❌ ОШИБКА: type_config не найден в user_data!")				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")		return WAIT_CONSTRUCTOR_CATEGORY		steps = type_config.get('steps', [])	print(f"  📋 Всего шагов: {len(steps)}")		if step_index >= len(steps):		# Все шаги пройдены - сохраняем		print(f"  ✅ Все шаги пройдены! Переход к сохранению")		print("=" * 60)		return await save_link(update, context)		step = steps[step_index]	print(f"  🎯 Шаг {step_index}: type={step['type']}, question='{step['question'][:50]}...'")		if step['type'] == 'choice':		# Показываем варианты выбора		keyboard = []		for opt in step['options']:			callback = f"choice_{opt['value']}"			print(f"    🟢 Вариант: {opt['label']} -> {callback}")			keyboard.append([InlineKeyboardButton(opt['label'], callback_data=callback)])				keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_types")])				await query.edit_message_text(			step['question'],			reply_markup=InlineKeyboardMarkup(keyboard),			parse_mode='HTML'		)		print(f"  ✅ Отправлен choice-шаг")		print("=" * 60)		return STEP_CHOICE		elif step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:		# Просим ввести текст		text = step['question']		if 'example' in step:			text += f"\n\n📌 *Пример:* {step['example']}"			print(f"  💡 Пример: {step['example']}")				# СОЗДАЕМ КЛАВИАТУРУ		keyboard = []				# Добавляем кнопку "Пропустить" если шаг опциональный		if step.get('optional'):			keyboard.append([InlineKeyboardButton("⏭️ Пропустить", callback_data="skip_step")])				keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous")])				await query.edit_message_text(			text,			reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,			parse_mode='HTML'		)		print(f"  ✅ Отправлен input-шаг (ожидание ввода)")		print("=" * 60)				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {STEP_INPUT}")		return STEP_INPUTasync def handle_skip(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Пропустить опциональный шаг"""	print("\n" + "=" * 60)	print("⏭️ handle_skip ВЫЗВАН")		query = update.callback_query	await query.answer()		step_index = context.user_data.get('step_index', 0)	type_config = context.user_data.get('type_config')	steps = type_config.get('steps', [])		print(f"  📍 Пропускаем шаг {step_index}")		# Сохраняем None для пропущенного поля	step = steps[step_index]	field = step.get('field')	if field:		context.user_data['collected_data'][field] = None		print(f"  💾 Поле {field} = None")				# Если пропустили шаг с заголовком (title)		if field == 'title':			choice = context.user_data['collected_data'].get('choice')			type_name = type_config.get('name', '')						# Маппинг выбора на русское название			type_map = {				'personal': 'Личный аккаунт',				'channel': 'Канал',				'group': 'Группа',				'bot': 'Бот',				'profile': 'Профиль',				'page': 'Страница',				'public': 'Публичная страница',				'invite': 'Приглашение'			}						if choice and choice in type_map:				# Сохраняем автоматическое название				context.user_data['collected_data']['title'] = f"{type_name} {type_map[choice]}"				print(f"  💾 Авто-название: {type_name} {type_map[choice]}")		# Переходим к следующему шагу	context.user_data['step_index'] = step_index + 1		# Если это был последний шаг - сохраняем	if step_index + 1 >= len(steps):		print(f"  📍 Это был последний шаг, сохраняем")				# ИСПОЛЬЗУЕМ query.message, А НЕ update.message!		class FakeQuery:			def __init__(self, message):				self.message = message						async def edit_message_text(self, text, **kwargs):				return await self.message.reply_text(text, **kwargs)				fake_query = FakeQuery(query.message)		return await save_link_with_query(update, context, fake_query)		print(f"  🔄 Переходим к шагу {step_index + 1}")	print("=" * 60)		return await process_current_step(update, context)async def handle_choice(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Обработка выбора из вариантов"""	print("\n" + "=" * 60)	print("🔧 handle_choice ВЫЗВАН")		print("🔧 handle_input ВЫЗВАН")		query = update.callback_query	await query.answer()		choice = query.data.replace("choice_", "")	step_index = context.user_data.get('step_index', 0)	type_config = context.user_data.get('type_config')		# В самом начале после получения type_config	print(f"  📋 ВСЕГО ШАГОВ В КОНФИГЕ: {len(type_config.get('steps', []))}")	for i, s in enumerate(type_config.get('steps', [])):		print(f"    шаг {i}: {s.get('type')} - {s.get('field', 'нет поля')}")		print(f"  📩 callback_data: {query.data}")	print(f"  🎯 Выбрано: {choice}")	print(f"  📍 Текущий шаг index: {step_index}")		step = type_config['steps'][step_index]	field = step.get('field', 'choice')		# Сохраняем выбор	context.user_data['collected_data'][field] = choice	print(f"  💾 Сохранено: collected_data['{field}'] = '{choice}'")		# СОХРАНЯЕМ ОРИГИНАЛЬНЫЙ ТИП ДЛЯ ВОССТАНОВЛЕНИЯ (если еще не сохранен)	if 'original_link_type' not in context.user_data:		context.user_data['original_link_type'] = context.user_data.get('link_type')		print(f"  💾 Сохранен оригинальный тип: {context.user_data['original_link_type']}")		# СОХРАНЯЕМ ПОЛНУЮ КОПИЮ ОРИГИНАЛЬНОГО КОНФИГА (если еще не сохранена)	if 'full_type_config' not in context.user_data:		# Делаем глубокую копию конфига, чтобы не изменять оригинал		import copy		context.user_data['full_type_config'] = copy.deepcopy(type_config)		print(f"  💾 Сохранена полная копия конфига ({len(type_config.get('steps', []))} шагов)")		# ПОЛУЧАЕМ ВСЕ ШАГИ	steps = type_config.get('steps', [])		# ОБРЕЗАЕМ ШАГИ В ЗАВИСИМОСТИ ОТ ВЫБОРА	type_name = type_config.get('name')		if type_name == "Facebook":		if choice == 'profile':			# Оставляем: шаг 0 (заголовок), шаг 1 (выбор), шаг 2 (username)			type_config['steps'] = [steps[0], steps[1], steps[2]]			context.user_data['step_index'] = 2		elif choice == 'page':			# Создаем шаги для страницы на основе существующих			page_title_step = steps[2].copy()			page_title_step['field'] = 'page_title'			page_title_step['question'] = steps[3]['question']  # берем вопрос из шага 3						page_username_step = steps[2].copy()			page_username_step['field'] = 'page_username'			page_username_step['question'] = steps[4]['question']  # берем вопрос из шага 4						type_config['steps'] = [steps[0], steps[1], page_title_step, page_username_step]			context.user_data['step_index'] = 2		elif choice == 'group':			# Создаем шаги для группы на основе существующих			group_title_step = steps[2].copy()			group_title_step['field'] = 'group_title'			group_title_step['question'] = steps[5]['question']  # берем вопрос из шага 5						group_username_step = steps[2].copy()			group_username_step['field'] = 'group_username'			group_username_step['question'] = steps[6]['question']  # берем вопрос из шага 6						type_config['steps'] = [steps[0], steps[1], group_title_step, group_username_step]			context.user_data['step_index'] = 2		elif type_name == "VK":		if choice == 'profile':			# Оставляем: шаг 0 (заголовок), шаг 1 (выбор), шаг 2 (profile_id)			type_config['steps'] = [steps[0], steps[1], steps[2]]			context.user_data['step_index'] = 2		elif choice == 'public':			# Создаем шаг для публичной страницы на основе шага 2			public_step = steps[2].copy()			public_step['field'] = 'public_id'			public_step['question'] = steps[3]['question']  # берем вопрос из шага 3			type_config['steps'] = [steps[0], steps[1], public_step]			context.user_data['step_index'] = 2		elif choice == 'group':			# Создаем шаг для группы на основе шага 2			group_step = steps[2].copy()			group_step['field'] = 'group_id'			group_step['question'] = steps[4]['question']  # берем вопрос из шага 4			type_config['steps'] = [steps[0], steps[1], group_step]			context.user_data['step_index'] = 2			elif type_name == "Telegram":		# Шаг 0 - choice, шаг 1 - title		current_step = steps[step_index]  # шаг 0 (choice)				for opt in current_step['options']:			if opt['value'] == choice:				target_idx = opt.get('next_step', 2)								# Проверяем что индекс существует				if target_idx < len(steps):					# СОЗДАЕМ НОВЫЙ КОНФИГ:					# - шаг 0: выбор (уже пройден)					# - шаг 1: title (будет показан СЕЙЧАС)					# - шаг 2: текстовый шаг для выбранного типа					type_config['steps'] = [						steps[0],  # choice (уже выбран)						steps[1],  # title (спрашиваем сейчас)						steps[target_idx]  # текстовый шаг (будет после title)					]					context.user_data['step_index'] = 1  # ← ВАЖНО! Идем на шаг title										# Авто-название (если пропустят title)					type_map = {						'personal': 'Личный аккаунт',						'channel': 'Канал',						'group': 'Группа',						'bot': 'Бот'					}					# Сохраняем на будущее					context.user_data['default_title'] = f"{type_name} {type_map[choice]}"					print(f"  💾 Дефолтное название: {context.user_data['default_title']}")				else:					# fallback					type_config['steps'] = [steps[0], steps[1], steps[2]]					context.user_data['step_index'] = 1				break				elif type_name == "Discord":		if choice == 'invite':			type_config['steps'] = [steps[0], steps[1], steps[2]]			context.user_data['step_index'] = 2		elif choice == 'profile':			profile_step = steps[2].copy()			profile_step['field'] = 'user_id'			profile_step[				'question'] = "👤 <b>Введите ID пользователя или ссылку на профиль</b>\n\nПримеры:\n• <code>568696023409754142</code>\n• <code>https://discord.com/users/568696023409754142</code>"			type_config['steps'] = [steps[0], steps[1], profile_step]			context.user_data['step_index'] = 2			else:		# Для других типов - стандартная логика		next_step = None		for opt in step['options']:			if opt['value'] == choice:				next_step = opt.get('next_step', step_index + 1)				print(f"  🔄 Для варианта '{choice}' следующий шаг: {next_step} (из конфига)")				break				if next_step is not None:			context.user_data['step_index'] = next_step		else:			context.user_data['step_index'] = step_index + 1		print(f"  🔄 Переходим к шагу {context.user_data['step_index']}")	print(f"  📊 Новый конфиг содержит {len(type_config.get('steps', []))} шагов")	print("=" * 60)	return await process_current_step(update, context)async def handle_input(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Обработка текстового ввода"""	print("\n" + "=" * 60)	print("🔧 handle_input ВЫЗВАН")		message = update.message	if not message or not message.text:		print(f"  ❌ Нет текста в сообщении")		return STEP_INPUT		text = message.text.strip()	user_id = message.from_user.id	print(f"  👤 user_id: {user_id}")	print(f"  📩 ввод: '{text}'")		step_index = context.user_data.get('step_index', 0)	type_config = context.user_data.get('type_config')		print(f"  📍 Текущий шаг index: {step_index}")		if not type_config:		print(f"  ❌ ОШИБКА: type_config не найден!")		await message.reply_text("❌ Ошибка, начни заново /addlink")				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")		return WAIT_CONSTRUCTOR_CATEGORY		steps = type_config.get('steps', [])	if step_index >= len(steps):		print(f"  ❌ ОШИБКА: step_index {step_index} вне диапазона (всего шагов {len(steps)})")		print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")		return WAIT_CONSTRUCTOR_CATEGORY		step = steps[step_index]	field = step.get('field', 'value')		# ===== ПРОВЕРКА ДЛИНЫ =====	if step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:		max_len = step.get('max_length', 255)		if len(text) > max_len:			# Определяем название поля для сообщения об ошибке			field_label = step.get('question', 'значение').replace('<b>', '').replace('</b>', '')[:30]						error_msg = (				f"❌ **Слишком длинное {field_label}!**\n\n"				f"📏 Максимальная длина: **{max_len}** символов\n"				f"✏️ Вы ввели: **{len(text)}** символов\n\n"				f"👉 Пожалуйста, сократите и отправьте **снова**"			)						print(f"  ❌ Ошибка длины: {len(text)} > {max_len}")			await message.reply_text(				error_msg,				parse_mode='Markdown',				reply_markup=InlineKeyboardMarkup([[					InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous"),					InlineKeyboardButton("❌ Отмена", callback_data="add_link")				]])			)						# Остаемся на том же шаге			return STEP_INPUT	# ===========================		# Сохраняем введенное значение	context.user_data['collected_data'][field] = text	print(f"  💾 Сохранено: collected_data['{field}'] = '{text}'")		# Переходим к следующему шагу	context.user_data['step_index'] = step_index + 1	print(f"  🔄 Переходим к шагу {step_index + 1}")		# Если следующий шаг - тоже ввод, отправляем подтверждение	if step_index + 1 < len(steps):		await message.reply_text("✅ Принято! Далее...")		print(f"  ✅ Отправлено подтверждение")		print("=" * 60)		# Создаем объект, похожий на CallbackQuery	class FakeQuery:		def __init__(self, message):			self.message = message			self.data = None				async def answer(self):			pass				async def edit_message_text(self, text, **kwargs):			return await self.message.reply_text(text, **kwargs)		fake_query = FakeQuery(update.message)		# Передаем фейковый query	return await process_current_step_with_query(update, context, fake_query)async def process_current_step_with_query(update: Update, context: ContextTypes.DEFAULT_TYPE, fake_query):	"""Версия process_current_step с готовым query и проверкой длины"""	print("\n" + "=" * 60)	print("🔧 process_current_step_with_query ВЫЗВАН")		# ===== ПРОВЕРЯЕМ, НЕ ПРИШЛО ЛИ СООБЩЕНИЕ С ДЛИННЫМ ТЕКСТОМ =====	if update.message and update.message.text:		print(f"\n🔍🔍🔍 ПОЛУЧЕНО СООБЩЕНИЕ: {update.message.text[:30]}...")				step_index = context.user_data.get('step_index', 0)		type_config = context.user_data.get('type_config')				print(f"📊 step_index: {step_index}")		print(f"📊 type_config: {type_config.get('name') if type_config else 'None'}")				if type_config:			steps = type_config.get('steps', [])			print(f"📊 steps length: {len(steps)}")						if step_index < len(steps):				step = steps[step_index]				print(f"📊 step type: {step['type']}")				print(f"📊 step field: {step.get('field')}")				print(f"📊 step max_length: {step.get('max_length')}")								# Если это текстовый шаг - проверяем длину				if step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:					print(f"✅ Шаг опознан как текстовый!")					value = update.message.text					max_len = step.get('max_length', 255)										print(f"📏 Длина введенного текста: {len(value)}")					print(f"📏 Максимальная длина: {max_len}")										if len(value) > max_len:						print(f"❌ Длина превышена! Должна быть ошибка!")												# ОПРЕДЕЛЯЕМ field_label						field_label = step.get('question', 'значение').replace('<b>', '').replace('</b>', '')[:30]												# СОЗДАЕМ error_msg						error_msg = (							f"❌ **Слишком длинное {field_label}!**\n\n"							f"📏 Максимальная длина: **{max_len}** символов\n"							f"✏️ Вы ввели: **{len(value)}** символов\n\n"							f"👉 Пожалуйста, сократите и отправьте **снова**"						)												# Отправляем сообщение об ошибке						await update.message.reply_text(							error_msg,							parse_mode='Markdown',							reply_markup=InlineKeyboardMarkup([[								InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous"),								InlineKeyboardButton("❌ Отмена", callback_data="add_link")							]])						)												# Остаемся на том же шаге						print(f"  ❌ Ошибка длины: {len(value)} > {max_len}")						return STEP_INPUT		step_index = context.user_data.get('step_index', 0)	type_config = context.user_data.get('type_config')		print(f"  📍 Текущий шаг index: {step_index}")	print(f"  📊 collected_data: {context.user_data.get('collected_data', {})}")		if not type_config:		print(f"  ❌ ОШИБКА: type_config не найден!")				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")		return WAIT_CONSTRUCTOR_CATEGORY		steps = type_config.get('steps', [])	print(f"  📋 Всего шагов: {len(steps)}")		if step_index >= len(steps):		print(f"  ✅ Все шаги пройдены! Переход к сохранению")		print("=" * 60)		return await save_link_with_query(update, context, fake_query)		step = steps[step_index]	print(f"  🎯 Шаг {step_index}: type={step['type']}, question='{step['question'][:50]}...'")		if step['type'] == 'choice':		# Показываем варианты выбора		keyboard = []		for opt in step['options']:			callback = f"choice_{opt['value']}"			print(f"    🟢 Вариант: {opt['label']} -> {callback}")			keyboard.append([InlineKeyboardButton(opt['label'], callback_data=callback)])				keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_types")])				await fake_query.edit_message_text(			step['question'],			reply_markup=InlineKeyboardMarkup(keyboard),			parse_mode='HTML'		)		print(f"  ✅ Отправлен choice-шаг")		print("=" * 60)		return STEP_CHOICE		elif step['type'] in ['text', 'phone', 'email', 'card', 'url', 'title']:		# Просим ввести текст		text = step['question']		if 'example' in step:			text += f"\n\n📌 *Пример:* {step['example']}"			print(f"  💡 Пример: {step['example']}")				# Добавляем информацию о максимальной длине		max_len = step.get('max_length', 255)		text += f"\n\n📏 *Максимум {max_len} символов*"				# СОЗДАЕМ КЛАВИАТУРУ		keyboard = []				# Добавляем кнопку "Пропустить" если шаг опциональный		if step.get('optional'):			keyboard.append([InlineKeyboardButton("⏭️ Пропустить", callback_data="skip_step")])				keyboard.append([InlineKeyboardButton("◀️ Назад", callback_data="back_to_previous")])				await fake_query.edit_message_text(			text,			reply_markup=InlineKeyboardMarkup(keyboard) if keyboard else None,			parse_mode='HTML'		)		print(f"  ✅ Отправлен input-шаг (ожидание ввода)")		print("=" * 60)				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {STEP_INPUT}")		return STEP_INPUTasync def save_link_with_query(update: Update, context: ContextTypes.DEFAULT_TYPE, fake_query):	"""Сохранить ссылку в БД (версия с fake_query)"""	print("\n" + "=" * 60)	print("💾 save_link_with_query ВЫЗВАН")		type_config = context.user_data.get('type_config')	collected = context.user_data.get('collected_data', {})	link_type = context.user_data.get('link_type')		# ОПРЕДЕЛЯЕМ user_id ПРАВИЛЬНО	if update.callback_query:		user_id = update.callback_query.from_user.id		print(f"  📩 из callback, user_id: {user_id}")	else:		user_id = update.message.from_user.id		print(f"  📩 из message, user_id: {user_id}")		# ===== 1. ВАЛИДАЦИЯ И ПАРСИНГ =====	url, error = await parse_and_validate(link_type, collected)		if error:		print(f"  ❌ Ошибка валидации: {error}")		await fake_query.edit_message_text(error)		# Возвращаемся на предыдущий шаг		context.user_data['step_index'] = max(0, context.user_data.get('step_index', 1) - 1)		return await process_current_step_with_query(update, context, fake_query)		# ===== 2. ФОРМИРОВАНИЕ НАЗВАНИЯ =====	title = collected.get('title')	if not title:		# Если название не ввели, берем из конфига		title = type_config.get('name', 'Ссылка')		# ===== 2. ФОРМИРОВАНИЕ НАЗВАНИЯ =====	title = collected.get('title')	if not title:		# Если название не ввели, берем из конфига		title = type_config.get('name', 'Ссылка')		# Если channel_name не указан, берем из channel_input	if not collected.get('channel_name') and collected.get('channel_input'):		channel_input = collected.get('channel_input')		channel_name = ""				# Очищаем от @ и https		if channel_input.startswith('@'):			channel_name = channel_input[1:]		elif 'youtube.com' in channel_input:			# Парсим из ссылки			import re			match = re.search(r'(?:youtube\.com/|@)([^/]+)', channel_input)			channel_name = match.group(1) if match else channel_input		else:			channel_name = channel_input				# Делаем первую букву заглавной		if channel_name:			channel_name = channel_name[0].upper() + channel_name[1:] if len(channel_name) > 1 else channel_name.upper()				collected['channel_name'] = channel_name		print(f"  💾 Автоматически установлено channel_name = {channel_name}")		# ===== 3. СОХРАНЕНИЕ В БД =====	conn = await get_db_connection()	try:		db_user = await get_or_create_user(conn, user_id, None, None, None)		page = await conn.fetchrow("SELECT id, username FROM pages WHERE user_id = $1", db_user['id'])		page_id = page['id'] if page else None		page_username = page['username'] if page else None				if not page_id:			await fake_query.edit_message_text("❌ Ошибка: страница не найдена")						print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")			return WAIT_CONSTRUCTOR_CATEGORY				# Определяем sort_order		max_order = await conn.fetchval(			"SELECT COALESCE(MAX(sort_order), 0) FROM links WHERE page_id = $1",			page_id		)		next_order = max_order + 1				# pay_details = все collected кроме title и тех полей что уже использованы		exclude_fields = ['title', 'choice']		pay_details = {k: v for k, v in collected.items() if k not in exclude_fields}				# ===== ОБРЕЗАЕМ ВСЕ СТРОКИ =====				# 1. Title - обычно VARCHAR(255)		if title and len(title) > 255:			title = title[:255]			print(f"⚠️ Title обрезан до 255 символов")				# 2. URL - обычно VARCHAR(500) или TEXT		if url and len(url) > 500:			url = url[:500]			print(f"⚠️ URL обрезан до 500 символов")				# 3. Icon - обычно VARCHAR(100)		icon = type_config.get('icon', '')		if icon and len(icon) > 100:			icon = icon[:100]			print(f"⚠️ Icon обрезана до 100 символов")				# 4. link_type - обычно VARCHAR(50)		if link_type and len(link_type) > 50:			link_type = link_type[:50]			print(f"⚠️ link_type обрезан до 50 символов")				# 5. JSON данные - подготавливаем и обрезаем		pay_details_json = json.dumps(pay_details, ensure_ascii=False) if pay_details else None		if pay_details_json and len(pay_details_json) > 10000:  # для TEXT поля			pay_details_json = pay_details_json[:10000]			print(f"⚠️ pay_details JSON обрезан до 10000 символов")				await conn.execute("""                           INSERT INTO links                           (page_id, title, url, icon, sort_order, link_type, category, pay_details, is_active)                           VALUES ($1, $2, $3, $4, $5, $6, $7, $8, true)		                   """,		                   page_id,		                   title,  # обрезанный		                   url,  # обрезанный		                   icon,  # обрезанный		                   next_order,		                   link_type,  # обрезанный		                   type_config.get('category'),		                   pay_details_json  # обрезанный JSON		                   )				# Получаем базовый URL из конфига (можно вынести в переменные окружения)		base_url = "http://localhost:8000"  # Замени на свой домен		page_link = f"{base_url}/{page_username}"				# Получаем человеческое название категории		category_id = type_config.get('category')		category_name = CATEGORIES.get(category_id, {}).get('name', category_id)				success_message = (			f"✅ <b>{title}</b> успешно добавлена!\n\n"			f"🌐 <b>Твоя страница:</b>\n"			f"👉 <a href='{page_link}'>{page_link}</a>\n"			f"На странице ссылка появится в разделе «{category_name}»\n\n"			f"📌 <b>Что дальше?</b>\n"			f"• Нажми <b>«Управление ссылками»</b> чтобы посмотреть все ссылки\n"			f"• Нажми <b>➕ «Добавить ещё»</b> чтобы добавить еще\n"			f"• Нажми <b>🏠 «Главное меню»</b> чтобы вернуться в начало"		)				await fake_query.edit_message_text(			success_message,			reply_markup=InlineKeyboardMarkup([				[					InlineKeyboardButton("📋 Управление ссылками", callback_data="links"),					InlineKeyboardButton("➕ Добавить ещё", callback_data="add_link")				],				[					InlineKeyboardButton("🏠 Главное меню", callback_data="start")				]			]),			parse_mode='HTML',			disable_web_page_preview=True		)				print(f"  ✅ Ссылка сохранена, страница: {page_link}")		except Exception as e:		print(f"  ❌ ОШИБКА: {e}")		await fake_query.edit_message_text("❌ Ошибка при сохранении")	finally:		await conn.close()		context.user_data.clear()	return ConversationHandler.ENDasync def process_current_step_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Версия process_current_step для сообщений (без query)"""	print("\n" + "=" * 60)	print("🔧 process_current_step_callback (для сообщений)")		# Искусственно создаем callback_query для переиспользования функции	class FakeQuery:		def __init__(self, message):			self.message = message			self.data = None				async def edit_message_text(self, text, **kwargs):			print(f"  📝 FakeQuery.edit_message_text: '{text[:50]}...'")			return await self.message.reply_text(text, **kwargs)				async def answer(self):			pass		fake_query = FakeQuery(update.message)		print("=" * 60)		print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {STEP_INPUT}")	return await process_current_step_with_query(update, context, fake_query)  # ← ВОТ ТУТ ИСПРАВЛЕНИЕasync def save_link(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Сохранить ссылку в БД"""	print("\n" + "=" * 60)	print("💾 save_link ВЫЗВАН")		# Определяем, откуда пришли	if update.callback_query:		query = update.callback_query		user_id = query.from_user.id		print(f"  📩 из callback, user_id: {user_id}")	else:		# Пришли из сообщения (после handle_input)		# Создаем заглушку для единообразия		class FakeQuery:			def __init__(self, message):				self.message = message						async def edit_message_text(self, text, **kwargs):				return await self.message.reply_text(text, **kwargs)				query = FakeQuery(update.message)		user_id = update.message.from_user.id		print(f"  📩 из message, user_id: {user_id}")		type_config = context.user_data.get('type_config')	collected = context.user_data.get('collected_data', {})		print(f"  📋 type_config: {type_config.get('name') if type_config else 'None'}")	print(f"  📊 collected_data: {collected}")		if not type_config:		print(f"  ❌ ОШИБКА: type_config не найден!")		await query.edit_message_text("❌ Ошибка, начни заново")				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")		return WAIT_CONSTRUCTOR_CATEGORY		# Получаем page_id	page_id = await get_page_id(context, user_id)	print(f"  🆔 page_id: {page_id}")		if not page_id:		print(f"  ❌ ОШИБКА: страница не найдена для user_id {user_id}")		await query.edit_message_text("❌ Ошибка: страница не найдена")				print(f"  🔄 ВОЗВРАЩАЕМОЕ СОСТОЯНИЕ: {WAIT_CONSTRUCTOR_CATEGORY}")		return WAIT_CONSTRUCTOR_CATEGORY		# Формируем данные для сохранения	title = collected.get('title') or type_config['name']	print(f"  📝 title: '{title}'")		# Определяем URL (может быть из разных полей)	url = collected.get('url') or collected.get('phone') or collected.get('username') or ''	print(f"  🔗 url: '{url}'")		# Остальные данные уходят в pay_details	pay_details = {k: v for k, v in collected.items() if k not in ['title', 'url']}	print(f"  📦 pay_details: {pay_details}")		# ===== ОБРЕЗАЕМ ВСЕ СТРОКИ =====		# 1. Title - обычно VARCHAR(255)	if title and len(title) > 255:		title = title[:255]		print(f"⚠️ Title обрезан до 255 символов")		# 2. URL - обычно VARCHAR(500) или TEXT	if url and len(url) > 500:		url = url[:500]		print(f"⚠️ URL обрезан до 500 символов")		# 3. Icon - обычно VARCHAR(100)	icon = type_config.get('icon', '')	if icon and len(icon) > 100:		icon = icon[:100]		print(f"⚠️ Icon обрезана до 100 символов")		# 4. link_type - обычно VARCHAR(50)	link_type = context.user_data.get('link_type')	if link_type and len(link_type) > 50:		link_type = link_type[:50]		print(f"⚠️ link_type обрезан до 50 символов")		# 5. JSON данные - подготавливаем и обрезаем	pay_details_json = json.dumps(pay_details, ensure_ascii=False) if pay_details else None	if pay_details_json and len(pay_details_json) > 10000:  # для TEXT поля		pay_details_json = pay_details_json[:10000]		print(f"⚠️ pay_details JSON обрезан до 10000 символов")		# Сохраняем в БД	conn = await get_db_connection()	try:		# Проверяем sort_order		max_order = await conn.fetchval(			"SELECT COALESCE(MAX(sort_order), 0) FROM links WHERE page_id = $1",			page_id		)		next_order = max_order + 1		print(f"  🔢 sort_order: {next_order}")				await conn.execute("""                           INSERT INTO links                           (page_id, title, url, icon, sort_order, link_type, category, pay_details, is_active)                           VALUES ($1, $2, $3, $4, $5, $6, $7, $8, true)		                   """,		                   page_id,		                   title,  # обрезанный		                   url,  # обрезанный		                   icon,  # обрезанный		                   next_order,		                   link_type,  # обрезанный		                   type_config.get('category'),		                   pay_details_json  # обрезанный JSON		                   )				print(f"  ✅ Ссылка успешно сохранена в БД!")				await query.edit_message_text(			f"✅ **{title}** успешно добавлена!",			reply_markup=InlineKeyboardMarkup([[				InlineKeyboardButton("📋 Управление ссылками", callback_data="links"),				InlineKeyboardButton("➕ Еще ссылку", callback_data="add_link")			]]),			parse_mode='Markdown'		)		print(f"  ✅ Отправлено подтверждение пользователю")		except Exception as e:		print(f"  ❌ ОШИБКА сохранения: {e}")		logger.error(f"Ошибка сохранения: {e}", exc_info=True)		await query.edit_message_text("❌ Ошибка при сохранении")	finally:		await conn.close()		print("=" * 60)	# Очищаем данные диалога	context.user_data.clear()	return ConversationHandler.ENDasync def back_to_categories(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Вернуться к выбору категории"""	print("\n" + "=" * 60)	print("🔙 back_to_categories ВЫЗВАН")		query = update.callback_query	await query.answer()		print(f"  📩 callback_data: {query.data}")	print(f"  🧹 Очистка user_data")		context.user_data.clear()		print("=" * 60)	return await start_constructor(update, context)async def back_to_types(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Вернуться к выбору типа в текущей категории"""	print("\n" + "=" * 60)	print("🔙 back_to_types ВЫЗВАН")		query = update.callback_query	await query.answer()		print(f"  📩 callback_data: {query.data}")		category = context.user_data.get('category')	print(f"  🏷️  Текущая категория: {category}")		if category:		# ПОЛНОСТЬЮ ОЧИЩАЕМ ДАННЫЕ КОНСТРУКТОРА		context.user_data.pop('step_index', None)		context.user_data.pop('collected_data', None)		context.user_data.pop('type_config', None)		context.user_data.pop('original_link_type', None)		print(f"  🧹 Очищены все данные конструктора")				# ПОКАЗЫВАЕМ ТИПЫ		cat_data = CATEGORIES.get(category, {})		text = f"{cat_data.get('icon', '📁')} **{cat_data.get('name', category)}**\n\n{cat_data.get('description', '')}\n\n👇 **Выбери тип:**"		keyboard = build_types_keyboard(category)				await query.edit_message_text(text, reply_markup=keyboard, parse_mode='Markdown')		print(f"  ✅ Показаны типы для {category}")		print("=" * 60)				print(f"  🔄 ДИАЛОГ ПЕРЕХОДИТ В СОСТОЯНИЕ: WAIT_CONSTRUCTOR_TYPE ({WAIT_CONSTRUCTOR_TYPE})")		return WAIT_CONSTRUCTOR_TYPE		print(f"  ⚠️ Категория не найдена, возврат к началу")	print("=" * 60)	return await back_to_categories(update, context)async def cancel_constructor(update: Update, context: ContextTypes.DEFAULT_TYPE):	"""Отмена создания ссылки"""	print("\n" + "=" * 60)	print("❌ cancel_constructor ВЫЗВАН")		query = update.callback_query	if query:		await query.answer()		print(f"  📩 callback_data: {query.data}")		print(f"  🧹 Очистка user_data")	context.user_data.clear()		print("=" * 60)		# СРАЗУ В ГЛАВНОЕ МЕНЮ!	from bot.handlers import start_handler	return await start_handler(update, context)